def minPath(grid, k):
    N = len(grid)
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    visited = set()
    heap = []

    for i in range(N):
        for j in range(N):
            heappush(heap, (grid[i][j], i, j, [grid[i][j]]))

    while heap:
        value, x, y, path = heappop(heap)
        if len(path) == k:
            return path
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N and (nx, ny, len(path)) not in visited:
                visited.add((nx, ny, len(path)))
                heappush(heap, (value + grid[nx][ny], nx, ny, path + [grid[nx][ny]]))

    return []
